const crypto = require('crypto');
const config = $('Configuration (EDIT ME)').first().json;
const item = $input.first();

const header = (item.json.headers && item.json.headers['x-sellf-signature']) || '';
const rawBody = item.binary && item.binary.data
  ? Buffer.from(item.binary.data.data, 'base64').toString('utf8')
  : JSON.stringify(item.json.body || {});

let t = null;
let v1 = null;
for (const part of header.split(',')) {
  const eq = part.indexOf('=');
  if (eq === -1) continue;
  const key = part.slice(0, eq).trim();
  const value = part.slice(eq + 1).trim();
  if (key === 't') t = value;
  else if (key === 'v1') v1 = value;
}

let valid = false;
if (t && v1 && config.webhookSecret) {
  const expected = crypto.createHmac('sha256', config.webhookSecret).update(`${t}.${rawBody}`).digest('hex');
  const withinTolerance = Math.abs(Math.floor(Date.now() / 1000) - Number(t)) <= 300;
  const sameLength = expected.length === v1.length;
  valid = withinTolerance && sameLength && crypto.timingSafeEqual(Buffer.from(expected, 'hex'), Buffer.from(v1, 'hex'));
}

return [{ json: { valid, body: JSON.parse(rawBody) } }];

const data = $input.first().json.body.data;

return [{
  json: {
    email: data.customer.email,
    firstName: data.customer.firstName || '',
    productName: data.product.name,
    amount: data.order.amount / 100,
    currency: data.order.currency.toUpperCase(),
    sessionId: data.order.sessionId,
    paymentIntentId: data.order.paymentIntentId,
    needsInvoice: data.invoice?.needsInvoice || false,
    invoiceNip: data.invoice?.nip || null,
    invoiceCompany: data.invoice?.companyName || null,
    invoiceAddress: data.invoice?.address || null,
    invoiceCity: data.invoice?.city || null,
    invoicePostalCode: data.invoice?.postalCode || null,
    invoiceCountry: data.invoice?.country || 'PL'
  }
}];

const d = $input.first().json;
const config = $('Configuration (EDIT ME)').first().json;
const today = new Date().toISOString().split('T')[0];

// Build invoice number from session ID suffix - adjust this scheme if you have your own
const suffix = (d.sessionId || 'XXXX').slice(-4).toUpperCase();
const invoiceNumber = `FV/${today.replace(/-/g, '/')}/${suffix}`;

const buyerCity = d.invoicePostalCode
  ? `${d.invoicePostalCode} ${d.invoiceCity}`
  : d.invoiceCity || '-';

const seller = {
  nip: config.sellerNip,
  name: config.sellerName,
  address: {
    street: config.sellerStreet,
    city: config.sellerCity
  }
};

return [{
  json: {
    invoiceNumber,
    issueDate: today,
    saleDate: today,
    issuePlace: seller.address.city.split(' ').slice(1).join(' ') || 'Warszawa',
    currency: d.currency || 'PLN',
    type: 'VAT',
    seller,
    buyer: {
      nip: d.invoiceNip,
      name: d.invoiceCompany || d.email,
      address: {
        street: d.invoiceAddress || '-',
        city: buyerCity,
        country: d.invoiceCountry || 'PL'
      }
    },
    items: [
      {
        name: d.productName,
        unit: 'szt.',
        quantity: 1,
        unitPrice: d.amount,
        vatRate: config.defaultVatRate
      }
    ],
    payment: {
      paid: true,
      date: today,
      method: 'transfer'
    },
    // Pass-through for error logging
    _meta: {
      sessionId: d.sessionId,
      paymentIntentId: d.paymentIntentId,
      buyerEmail: d.email
    }
  }
}];
